#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

/*
 * I/O Device Virtualization Simulation
 * Demonstrates three approaches: 
 * 1. Full Device Emulation
 * 2. Paravirtualized I/O (Virtio-like)
 * 3. Direct I/O Passthrough (SR-IOV)
 */

#define MAX_VMS 4
#define EMULATED_DEVICE_NAME "Intel E1000"

/* Device request structure */
typedef struct {
 int vm_id;
 char operation[16]; // read, write
 unsigned int sector; // for storage
 char data[512];
} io_request_t;

/* Simulated physical device */
typedef struct {
 char name[64];
 bool busy;
 int throughput_mbps;
} physical_device_t;

/* VM structure */
typedef struct {
 int vm_id;
 char io_driver_type[32]; // "emulated", "paravirtual", "passthrough"
 bool has_virtual_function;
} vm_t;

/* ============================================================================
 * METHOD 1: Full Device Emulation
 * Hypervisor emulates a well-known device, guest uses standard driver
 * ============================================================================ */

void handle_emulated_io(physical_device_t *dev, io_request_t *req) {
 printf("[Emulation] VM%d: Request to %s at sector %u\n", 
 req->vm_id, req->operation, req->sector);

 // Hypervisor translates emulated device requests to physical device
 printf("[Emulation] Hypervisor: Translating to %s, performing I/O...\n", dev->name);

 // Simulate context switches and emulation overhead
 printf("[Emulation] Context switches: Guest->Hypervisor->Device->Hypervisor->Guest\n");
 printf("[Emulation] Overhead: High - full instruction emulation required\n");
}

/* ============================================================================
 * METHOD 2: Paravirtualized I/O (Virtio-style)
 * Guest uses hypervisor-aware drivers, direct communication
 * ============================================================================ */

typedef struct {
 char queue_name[32];
 void *shared_buffer;
 bool needs_notification;
} virtqueue_t;

void handle_paravirtual_io(vm_t *vm, io_request_t *req) {
 printf("[Paravirtual] VM%d: Using %s driver, sending hypercall\n",
 vm->vm_id, vm->io_driver_type);

 // Direct communication with hypervisor via shared memory (virtqueue)
 printf("[Paravirtual] Hypervisor: Received request via shared memory queue\n");
 printf("[Paravirtual] Performing I/O directly on %s\n", req->operation);

 // Much fewer context switches
 printf("[Paravirtual] Context switches: Guest->Hypervisor (minimal overhead)\n");
 printf("[Paravirtual] Performance: Near-native with Virtio\n");
}

/* ============================================================================
 * METHOD 3: Direct I/O Passthrough (SR-IOV)
 * VM gets direct access to virtual function of physical device
 * ============================================================================ */

typedef struct {
 int pf_id; // Physical function
 int vf_id; // Virtual function
 int vm_assigned; // VM that owns this VF
 bool active;
} virtual_function_t;

void setup_sr_iov(physical_device_t *dev, virtual_function_t *vfs, int num_vfs) {
 printf("[SR-IOV] Physical device %s supports Single Root I/O Virtualization\n", 
 dev->name);

 for (int i = 0; i < num_vfs; i++) {
 vfs[i].pf_id = 0;
 vfs[i].vf_id = i;
 vfs[i].vm_assigned = -1;
 vfs[i].active = false;
 printf("[SR-IOV] Created Virtual Function VF%d\n", i);
 }
}

void handle_passthrough_io(virtual_function_t *vf, io_request_t *req) {
 printf("[Passthrough] VM%d: Direct access to VF%d (no hypervisor involvement)\n",
 req->vm_id, vf->vf_id);

 // VM driver talks directly to device
 printf("[Passthrough] VF%d: Performing %s at sector %u\n",
 vf->vf_id, req->operation, req->sector);

 printf("[Passthrough] Context switches: None - direct DMA to VM memory\n");
 printf("[Passthrough] Performance: Near-native, ideal for high-throughput\n");
}

/* ============================================================================
 * Main: Demonstrate all three I/O virtualization methods
 * ============================================================================ */

int main() {
 printf("=== I/O Device Virtualization Demonstration ===\n\n");

 // Setup physical device
 physical_device_t nvme_device;
 strcpy(nvme_device.name, "NVMe SSD");
 nvme_device.busy = false;
 nvme_device.throughput_mbps = 3500;

 // Create VMs with different I/O methods
 vm_t vms[MAX_VMS];

 // VM1: Full emulation (legacy)
 vms[0].vm_id = 1;
 strcpy(vms[0].io_driver_type, "e1000");
 vms[0].has_virtual_function = false;

 // VM2: Paravirtualized (modern Linux)
 vms[1].vm_id = 2;
 strcpy(vms[1].io_driver_type, "virtio-blk");
 vms[1].has_virtual_function = false;

 // VM3: SR-IOV passthrough
 vms[2].vm_id = 3;
 strcpy(vms[2].io_driver_type, "vfio-pci");
 vms[2].has_virtual_function = true;

 // Setup SR-IOV virtual functions
 virtual_function_t vfs[2];
 setup_sr_iov(&nvme_device, vfs, 2);
 vfs[0].vm_assigned = 3; // Assign VF0 to VM3
 vfs[0].active = true;

 // Create sample I/O request
 io_request_t request;
 request.vm_id = 1;
 strcpy(request.operation, "read");
 request.sector = 1024;
 strcpy(request.data, "");

 // Demonstrate each method
 printf("\n--- Method 1: Full Device Emulation ---\n");
 request.vm_id = 1;
 handle_emulated_io(&nvme_device, &request);

 printf("\n--- Method 2: Paravirtualized I/O ---\n");
 request.vm_id = 2;
 handle_paravirtual_io(&vms[1], &request);

 printf("\n--- Method 3: Direct Passthrough (SR-IOV) ---\n");
 request.vm_id = 3;
 handle_passthrough_io(&vfs[0], &request);

 printf("\n=== Comparison ===\n");
 printf("| Method | Compatibility | Performance | Complexity |\n");
 printf("|-----------------|---------------|-------------|------------|\n");
 printf("| Full Emulation | High | Low | Low |\n");
 printf("| Paravirtual | Medium | High | Medium |\n");
 printf("| SR-IOV Passthrough | Low | Highest | High |\n");

 return 0;
}
